import redis
import sys

class AdvancedCacheClient:
    def __init__(self, host='localhost', port=6379, db=0):
        self.redis_client = redis.Redis(host=host, port=port, db=db, decode_responses=True)
    
    def execute_lua_script(self, lua_script, keys=None, args=None):
        """
        Execute Lua script with dynamic parameters
        """
        try:
            if keys is None:
                keys = []
            if args is None:
                args = []
            
            result = self.redis_client.eval(lua_script, len(keys), *keys, *args)
            return result
        except Exception as e:
            print(f"Error executing Lua script: {e}")
            return None
    
    def get_cache_stats(self):
        """Get basic cache statistics"""
        try:
            stats = self.redis_client.info()
            return {
                'connected': True,
                'used_memory': stats.get('used_memory_human'),
                'connected_clients': stats.get('connected_clients'),
                'total_commands_processed': stats.get('total_commands_processed')
            }
        except Exception as e:
            return {'connected': False, 'error': str(e)}

